import{c as a,Q as t,j as r,m as i}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Agents — claude.com/blog","description":"","frontmatter":{"title":"Agents — claude.com/blog","type":"index"},"headers":[],"relativePath":"research/claude-blog/agents/index.md","filePath":"research/claude-blog/agents/index.md","lastUpdated":1779935873000}'),l={name:"research/claude-blog/agents/index.md"};function o(n,e,s,h,u,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="agents-—-claude-com-blog" tabindex="-1">Agents — claude.com/blog <a class="header-anchor" href="#agents-—-claude-com-blog" aria-label="Permalink to &quot;Agents — claude.com/blog&quot;">​</a></h1><blockquote><p>收錄自 <a href="https://claude.com/blog/category/agents" target="_blank" rel="noreferrer">claude.com/blog/category/agents</a> · 19 篇文章 · 2025-11-13 ~ 2026-05-13 最後更新：2026-05-16</p></blockquote><hr><h2 id="best-practices-for-computer-and-browser-use-with-claude" tabindex="-1">Best practices for computer and browser use with Claude <a class="header-anchor" href="#best-practices-for-computer-and-browser-use-with-claude" aria-label="Permalink to &quot;Best practices for computer and browser use with Claude&quot;">​</a></h2><p><strong>Date:</strong> 2026-05-13 | <strong>URL:</strong> <a href="https://claude.com/blog/best-practices-for-computer-and-browser-use-with-claude" target="_blank" rel="noreferrer">https://claude.com/blog/best-practices-for-computer-and-browser-use-with-claude</a></p><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>整合 Claude 電腦/瀏覽器操作能力的實作指南。涵蓋截圖解析度優化、內容排序、模型選擇、Context 管理與 Prompt Injection 防護。適用 Claude 4.6 family 及 Opus 4.7。</p><h3 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>截圖預縮放：傳入 API 前先縮放（4.6 family：1568px/1.15MP；Opus 4.7：2576px/3.75MP）</li><li>內容排序：文字指令放在圖片之前，提升點擊準確率</li><li>模型選擇：Sonnet 4.6 機械精度佳；Opus 4.7 兼具點擊精度與推理能力</li><li>Thinking Effort：Opus 4.7 用 <code>high</code>；Claude 4.6 用 <code>medium</code>（<code>low</code> 成本敏感場景亦有效）</li><li>Context 管理：Prompt Caching + rolling buffer（保留最近 3 張截圖，每 25 張批次清理）</li><li><code>computer_20251124</code> 工具含內建 Prompt Injection classifier（免費）</li></ul><hr><h2 id="building-ai-agents-for-the-enterprise" tabindex="-1">Building AI agents for the enterprise <a class="header-anchor" href="#building-ai-agents-for-the-enterprise" aria-label="Permalink to &quot;Building AI agents for the enterprise&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-30 | <strong>URL:</strong> <a href="https://claude.com/blog/building-ai-agents-for-the-enterprise" target="_blank" rel="noreferrer">https://claude.com/blog/building-ai-agents-for-the-enterprise</a></p><h3 id="summary-1" tabindex="-1">Summary <a class="header-anchor" href="#summary-1" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>企業 AI 轉型指南：應對「Agentic 思維鴻溝」、員工技能升級、流程壓縮三大支柱。40% 員工使用 AI（2023 年 20%）。案例：L&#39;Oreal、Lyft、Rakuten。</p><h3 id="key-points-1" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-1" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>克服 Agentic 思維鴻溝：為何部分 AI 部署產生複合效益而其他停滯</li><li>員工技能升級：與組織工作流對齊的 AI 培訓最佳實踐</li><li>流程壓縮：保持人工監督的同時精簡資訊密集流程</li><li>Claude Cowork 六個月部署框架</li><li>三支柱策略：員工培訓 + 目標應用 + 未來產品開發</li></ul><hr><h2 id="claude-api-skill-now-in-coderabbit-jetbrains-resolve-ai-and-warp" tabindex="-1">Claude API skill now in CodeRabbit, JetBrains, Resolve AI, and Warp <a class="header-anchor" href="#claude-api-skill-now-in-coderabbit-jetbrains-resolve-ai-and-warp" aria-label="Permalink to &quot;Claude API skill now in CodeRabbit, JetBrains, Resolve AI, and Warp&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-29 | <strong>URL:</strong> <a href="https://claude.com/blog/claude-api-skill" target="_blank" rel="noreferrer">https://claude.com/blog/claude-api-skill</a></p><h3 id="summary-2" tabindex="-1">Summary <a class="header-anchor" href="#summary-2" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p><code>claude-api</code> Skill 擴展至四大開發工具。提供 Prompt Caching 優化、Agent 架構指引、Model 遷移輔助、Managed Agents 設定。開源於 <code>anthropics/skills</code>，20 行 CI 設定即可整合。</p><h3 id="key-points-2" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-2" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>快取最佳化、Agent 架構（context compaction）、模型遷移（Opus 4.7）、Managed Agents 設定</li><li>CodeRabbit：減少 Agent 建構時的 review 意外</li><li>JetBrains：Claude 升級轉為引導式 IDE 工作流</li><li>Warp：開發者無需離開 terminal 查閱 API 參數</li><li>開源：<code>anthropics/skills</code> on GitHub；約 20 行 CI 設定即可整合</li></ul><hr><h2 id="product-development-in-the-agentic-era" tabindex="-1">Product development in the agentic era <a class="header-anchor" href="#product-development-in-the-agentic-era" aria-label="Permalink to &quot;Product development in the agentic era&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-29 | <strong>URL:</strong> <a href="https://claude.com/blog/product-development-in-the-agentic-era" target="_blank" rel="noreferrer">https://claude.com/blog/product-development-in-the-agentic-era</a></p><h3 id="summary-3" tabindex="-1">Summary <a class="header-anchor" href="#summary-3" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Jess Yan（Claude Managed Agents PM）分享 AI 如何將 PM 工作從行政性轉為策略性創意工作。用 Claude 自動化操作任務，用 Claude Code 針對特定需求建立自訂 Agent。</p><h3 id="key-points-3" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-3" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>工作流演進：Claude Cowork 做開放性研究/發現；Claude Code 建立特定操作 Agent</li><li>API 開發方式：對照 API 規格直接建立 Agent 原型，比多週文件審查更快發現設計問題</li><li>三類 Agent：分析型（查詢內部 DB）、情緒監控型（掃描開發者回饋）、Demo 建立型（活動演示）</li><li>核心觀點：自動化讓 PM 回歸本職工作——策略、創意和人員協作</li></ul><hr><h2 id="building-agents-that-reach-production-systems-with-mcp" tabindex="-1">Building agents that reach production systems with MCP <a class="header-anchor" href="#building-agents-that-reach-production-systems-with-mcp" aria-label="Permalink to &quot;Building agents that reach production systems with MCP&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-22 | <strong>URL:</strong> <a href="https://claude.com/blog/building-agents-that-reach-production-systems-with-mcp" target="_blank" rel="noreferrer">https://claude.com/blog/building-agents-that-reach-production-systems-with-mcp</a></p><h3 id="summary-4" tabindex="-1">Summary <a class="header-anchor" href="#summary-4" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>MCP（Model Context Protocol）已成為生產環境 Agent 的標準化基礎層，月下載量超過 3 億次。Tool Search 等 context 效率模式可將複雜工作流的 token 使用量減少 85% 以上。</p><h3 id="key-points-4" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-4" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>MCP 成為雲端生產系統的共通層（Claude Cowork、Claude Managed Agents 底層）</li><li>有效 MCP server：以意圖分組工具（intent-grouped），而非逐一映射 API</li><li>Tool Search 模式降低 85%+ token 用量</li><li>MCP 與 Skill 常搭配成 plugin，提供統一的領域知識入口</li></ul><hr><h2 id="preparing-your-security-program-for-ai-accelerated-offense" tabindex="-1">Preparing your security program for AI-accelerated offense <a class="header-anchor" href="#preparing-your-security-program-for-ai-accelerated-offense" aria-label="Permalink to &quot;Preparing your security program for AI-accelerated offense&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-10 | <strong>URL:</strong> <a href="https://claude.com/blog/preparing-your-security-program-for-ai-accelerated-offense" target="_blank" rel="noreferrer">https://claude.com/blog/preparing-your-security-program-for-ai-accelerated-offense</a></p><h3 id="summary-5" tabindex="-1">Summary <a class="header-anchor" href="#summary-5" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>AI 模型正大幅加速漏洞發現與利用速度，組織必須透過七大優先行動調整安全防禦姿態，防禦方同樣可以運用相同的 AI 能力自動化安全操作。</p><h3 id="key-points-5" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-5" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>CISA KEV：網際網路面向系統 24 小時修補目標</li><li>透過自動化、分類 Agent 擴展漏洞管理規模</li><li>AI 掃描整合進開發流水線（安全左移）</li><li>採用零信任設計，以密碼學身份取代摩擦式存取控制</li></ul><hr><h2 id="multi-agent-coordination-patterns-five-approaches-and-when-to-use-them" tabindex="-1">Multi-agent coordination patterns: Five approaches and when to use them <a class="header-anchor" href="#multi-agent-coordination-patterns-five-approaches-and-when-to-use-them" aria-label="Permalink to &quot;Multi-agent coordination patterns: Five approaches and when to use them&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-10 | <strong>URL:</strong> <a href="https://claude.com/blog/multi-agent-coordination-patterns" target="_blank" rel="noreferrer">https://claude.com/blog/multi-agent-coordination-patterns</a></p><h3 id="summary-6" tabindex="-1">Summary <a class="header-anchor" href="#summary-6" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>五種多 Agent 協調模式完整框架，建議從最簡單模式開始，根據具體限制逐步演進。</p><h3 id="key-points-6" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-6" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li><strong>Generator-Verifier</strong>：最廣泛部署，適合有明確評估標準的品質輸出</li><li><strong>Orchestrator-Subagent</strong>：可預定、有界的子任務</li><li><strong>Agent Teams</strong>：持續協作的多步驟工作</li><li><strong>Message Bus</strong>：事件驅動非同步管道</li><li><strong>Shared State</strong>：Agent 需即時共享發現時</li></ul><hr><h2 id="harnessing-claude-s-intelligence-3-key-patterns-for-building-apps" tabindex="-1">Harnessing Claude&#39;s intelligence: 3 key patterns for building apps <a class="header-anchor" href="#harnessing-claude-s-intelligence-3-key-patterns-for-building-apps" aria-label="Permalink to &quot;Harnessing Claude&#39;s intelligence: 3 key patterns for building apps&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-02 | <strong>URL:</strong> <a href="https://claude.com/blog/harnessing-claudes-intelligence" target="_blank" rel="noreferrer">https://claude.com/blog/harnessing-claudes-intelligence</a></p><h3 id="summary-7" tabindex="-1">Summary <a class="header-anchor" href="#summary-7" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>三種隨模型能力演進的架構模式：通用工具、消除不必要抽象、Prompt Caching 邊界建立。靜態內容前置可降低高達 90% 成本。</p><h3 id="key-points-7" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-7" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>優先使用通用工具（bash、文字編輯器），非特定用途替代品</li><li>定期審計 Agent 框架中的過時假設</li><li>Prompt Caching：靜態內容前置可降 90% 成本</li><li>高風險操作提升為專用型別化工具呼叫</li></ul><hr><h2 id="common-workflow-patterns-for-ai-agents—and-when-to-use-them" tabindex="-1">Common workflow patterns for AI agents—and when to use them <a class="header-anchor" href="#common-workflow-patterns-for-ai-agents—and-when-to-use-them" aria-label="Permalink to &quot;Common workflow patterns for AI agents—and when to use them&quot;">​</a></h2><p><strong>Date:</strong> 2026-03-05 | <strong>URL:</strong> <a href="https://claude.com/blog/common-workflow-patterns-for-ai-agents-and-when-to-use-them" target="_blank" rel="noreferrer">https://claude.com/blog/common-workflow-patterns-for-ai-agents-and-when-to-use-them</a></p><h3 id="summary-8" tabindex="-1">Summary <a class="header-anchor" href="#summary-8" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>三種主要 Agent 工作流模式：Sequential（依賴任務）、Parallel（獨立並行）、Evaluator-Optimizer（迭代品質優化）。強調「從最簡單模式開始」。</p><h3 id="key-points-8" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-8" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>Sequential：任務有依賴時；Parallel：獨立並行任務</li><li>Evaluator-Optimizer 迴圈透過迭代回饋改善輸出品質</li><li>模式選擇應優先考慮簡單性，使用解決問題所需的最低複雜度</li><li>資源限制和任務結構應驅動架構決策</li></ul><hr><h2 id="cowork-and-plugins-for-finance" tabindex="-1">Cowork and plugins for finance <a class="header-anchor" href="#cowork-and-plugins-for-finance" aria-label="Permalink to &quot;Cowork and plugins for finance&quot;">​</a></h2><p><strong>Date:</strong> 2026-02-24 | <strong>URL:</strong> <a href="https://claude.com/blog/cowork-plugins-finance" target="_blank" rel="noreferrer">https://claude.com/blog/cowork-plugins-finance</a></p><h3 id="summary-9" tabindex="-1">Summary <a class="header-anchor" href="#summary-9" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Anthropic 為 Claude Cowork 推出金融專屬 plugin，包含五個領域（投行、股權研究、私募、財富管理），以及 FactSet 和 MSCI 連接器，讓金融專業人士在不切換工具的情況下完成端到端工作流。</p><h3 id="key-points-9" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-9" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>五個金融 plugin：投資銀行、股權研究、私募股權、財富管理</li><li>FactSet 和 MSCI 連接器直接整合金融數據平台</li><li>Excel 和 PowerPoint 跨應用工作流</li><li>Plugin 生態系加速金融服務領域的角色定製化</li></ul><hr><h2 id="cowork-and-plugins-for-teams-across-the-enterprise" tabindex="-1">Cowork and plugins for teams across the enterprise <a class="header-anchor" href="#cowork-and-plugins-for-teams-across-the-enterprise" aria-label="Permalink to &quot;Cowork and plugins for teams across the enterprise&quot;">​</a></h2><p><strong>Date:</strong> 2026-02-24 | <strong>URL:</strong> <a href="https://claude.com/blog/cowork-plugins-across-enterprise" target="_blank" rel="noreferrer">https://claude.com/blog/cowork-plugins-across-enterprise</a></p><h3 id="summary-10" tabindex="-1">Summary <a class="header-anchor" href="#summary-10" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>企業版 Cowork 新增私有 plugin 市場與管理員控制功能，超過 12 個預建跨部門 plugin 模板（HR、設計、工程、財務），以及跨 Excel/PowerPoint 的多步驟工作流協調。</p><h3 id="key-points-10" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-10" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>私有 plugin 市場讓組織集中控制批准的 plugin 和連接器</li><li>超過 12 個預建模板涵蓋 HR、設計、工程、財務等部門</li><li>管理員控制實現企業規模的治理和合規</li><li>跨應用工作流協調處理複雜多步驟流程</li></ul><hr><h2 id="customize-cowork-with-plugins" tabindex="-1">Customize Cowork with plugins <a class="header-anchor" href="#customize-cowork-with-plugins" aria-label="Permalink to &quot;Customize Cowork with plugins&quot;">​</a></h2><p><strong>Date:</strong> 2026-01-30 | <strong>URL:</strong> <a href="https://claude.com/blog/cowork-plugins" target="_blank" rel="noreferrer">https://claude.com/blog/cowork-plugins</a></p><h3 id="summary-11" tabindex="-1">Summary <a class="header-anchor" href="#summary-11" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Anthropic 為 Claude Cowork 推出 plugin 支援，讓使用者可捆綁 skill、connector、slash command 和 sub-agent 為特定角色和工作流定製 Claude。發布 11 個涵蓋銷售、財務、法律、行銷的開源 plugin。</p><h3 id="key-points-11" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-11" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>Plugin 捆綁 skill、connector、slash command 和 sub-agent</li><li>11 個開源 plugin 提供銷售、財務、法律、行銷模板</li><li>本地 plugin 儲存，未來支援組織範圍共享</li><li>讓團隊無需開發自訂 agent 即可定製 Claude</li></ul><hr><h2 id="building-multi-agent-systems-when-and-how-to-use-them" tabindex="-1">Building multi-agent systems: When and how to use them <a class="header-anchor" href="#building-multi-agent-systems-when-and-how-to-use-them" aria-label="Permalink to &quot;Building multi-agent systems: When and how to use them&quot;">​</a></h2><p><strong>Date:</strong> 2026-01-23 | <strong>URL:</strong> <a href="https://claude.com/blog/building-multi-agent-systems-when-and-how-to-use-them" target="_blank" rel="noreferrer">https://claude.com/blog/building-multi-agent-systems-when-and-how-to-use-them</a></p><h3 id="summary-12" tabindex="-1">Summary <a class="header-anchor" href="#summary-12" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>多 Agent 架構何時有真正價值的指南。三個適合場景：保護 context 不受污染、並行任務執行、利用專業工具或知識。超出這些場景，協調成本通常超過收益。</p><h3 id="key-points-12" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-12" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>三個適合場景：context 隔離、並行執行、專業工具/領域知識</li><li>超出這三個場景時，協調成本通常超過收益</li><li>大多數企業工作流使用單 Agent 架構更具成本效益</li></ul><hr><h2 id="building-agents-with-skills-equipping-agents-for-specialized-work" tabindex="-1">Building agents with Skills: Equipping agents for specialized work <a class="header-anchor" href="#building-agents-with-skills-equipping-agents-for-specialized-work" aria-label="Permalink to &quot;Building agents with Skills: Equipping agents for specialized work&quot;">​</a></h2><p><strong>Date:</strong> 2026-01-22 | <strong>URL:</strong> <a href="https://claude.com/blog/building-agents-with-skills-equipping-agents-for-specialized-work" target="_blank" rel="noreferrer">https://claude.com/blog/building-agents-with-skills-equipping-agents-for-specialized-work</a></p><h3 id="summary-13" tabindex="-1">Summary <a class="header-anchor" href="#summary-13" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Agent Skills 是將領域知識打包成組織化檔案集合的新範式。透過 Progressive Disclosure 管理 context window，通用 Agent + Skill 優於為每個領域建立專用 Agent。</p><h3 id="key-points-13" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-13" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>Skill 將領域知識、工作流和最佳實踐打包成可存取的檔案集合</li><li>Progressive Disclosure 按需載入 Skill 資訊，管理 context window</li><li>Skill 分類：foundational、partner、enterprise</li><li>Skill 內的可執行腳本無需離開 Agent 環境即可自動化</li></ul><hr><h2 id="eight-trends-defining-how-software-gets-built-in-2026" tabindex="-1">Eight trends defining how software gets built in 2026 <a class="header-anchor" href="#eight-trends-defining-how-software-gets-built-in-2026" aria-label="Permalink to &quot;Eight trends defining how software gets built in 2026&quot;">​</a></h2><p><strong>Date:</strong> 2026-01-21 | <strong>URL:</strong> <a href="https://claude.com/blog/eight-trends-defining-how-software-gets-built-in-2026" target="_blank" rel="noreferrer">https://claude.com/blog/eight-trends-defining-how-software-gets-built-in-2026</a></p><h3 id="summary-14" tabindex="-1">Summary <a class="header-anchor" href="#summary-14" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>2026 年 AI 如何改變軟體開發的八大趨勢。開發者在 60% 的工作中使用 AI，但只能「完全委派」0-20% 的任務，人工監督仍不可或缺。</p><h3 id="key-points-14" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-14" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>AI 用於 60% 的開發工作，但只有 0-20% 可完全委派</li><li>編程 Agent 是協作夥伴，非替代品，人工監督至關重要</li><li>組織四大優先任務：多 Agent 協調、人機監督擴展、擴展至非工程團隊、嵌入早期安全</li><li>Agentic 編碼擴展至產品、設計和業務團隊</li></ul><hr><h2 id="extending-claude-s-capabilities-with-skills-and-mcp-servers" tabindex="-1">Extending Claude&#39;s capabilities with skills and MCP servers <a class="header-anchor" href="#extending-claude-s-capabilities-with-skills-and-mcp-servers" aria-label="Permalink to &quot;Extending Claude&#39;s capabilities with skills and MCP servers&quot;">​</a></h2><p><strong>Date:</strong> 2025-12-19 | <strong>URL:</strong> <a href="https://claude.com/blog/extending-claude-capabilities-with-skills-mcp-servers" target="_blank" rel="noreferrer">https://claude.com/blog/extending-claude-capabilities-with-skills-mcp-servers</a></p><h3 id="summary-15" tabindex="-1">Summary <a class="header-anchor" href="#summary-15" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Skill 和 MCP server 如何協同增強 Claude 的能力。MCP 提供與外部工具的連接，Skill 教 Claude 如何有效使用這些連接。兩者共同確保 Agent 遵循機構特定流程。</p><h3 id="key-points-15" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-15" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>MCP server 提供與外部工具、數據源的連接</li><li>Skill 編碼程序知識和工作流邏輯，以有效利用 MCP</li><li>職責分離：MCP 負責連接，Skill 負責邏輯</li><li>此架構支援企業級可靠性和治理</li></ul><hr><h2 id="skills-for-organizations-partners-the-ecosystem" tabindex="-1">Skills for organizations, partners, the ecosystem <a class="header-anchor" href="#skills-for-organizations-partners-the-ecosystem" aria-label="Permalink to &quot;Skills for organizations, partners, the ecosystem&quot;">​</a></h2><p><strong>Date:</strong> 2025-12-18 | <strong>URL:</strong> <a href="https://claude.com/blog/organization-skills-and-directory" target="_blank" rel="noreferrer">https://claude.com/blog/organization-skills-and-directory</a></p><h3 id="summary-16" tabindex="-1">Summary <a class="header-anchor" href="#summary-16" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Anthropic 推出組織級 Skill 管理功能，Team 和 Enterprise 管理員可集中配置 Skill。同時發布 Skill 目錄（含 Notion、Canva、Figma、Atlassian 整合）和 Agent Skills 開放標準。</p><h3 id="key-points-16" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-16" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>組織管理：管理員可跨組織集中部署批准的 Skill</li><li>Skill 目錄：合作夥伴建置的整合（Notion、Canva、Figma、Atlassian）</li><li>Agent Skills 開放標準：跨 AI 平台的 Skill 可攜性</li><li>中央治理確保組織內一致的批准工作流</li></ul><hr><h2 id="how-to-create-skills-key-steps-limitations-and-examples" tabindex="-1">How to create Skills: Key steps, limitations, and examples <a class="header-anchor" href="#how-to-create-skills-key-steps-limitations-and-examples" aria-label="Permalink to &quot;How to create Skills: Key steps, limitations, and examples&quot;">​</a></h2><p><strong>Date:</strong> 2025-11-19 | <strong>URL:</strong> <a href="https://claude.com/blog/how-to-create-skills-key-steps-limitations-and-examples" target="_blank" rel="noreferrer">https://claude.com/blog/how-to-create-skills-key-steps-limitations-and-examples</a></p><h3 id="summary-17" tabindex="-1">Summary <a class="header-anchor" href="#summary-17" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>自訂 Skill 建立指南，五步驟流程，強調清晰描述對正確觸發的重要性。包含 PDF 處理和品牌指南等實際範例。</p><h3 id="key-points-17" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-17" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>五步驟流程：從概念到部署的結構化 Skill 建立</li><li>清晰的 Skill 描述對正確觸發和發現至關重要</li><li>實際範例（PDF 處理、品牌指南）展示如何編碼機構知識</li><li>Skill 標準化輸出，確保組織一致性</li></ul><hr><h2 id="skills-explained-how-skills-compares-to-prompts-projects-mcp-and-subagents" tabindex="-1">Skills explained: How Skills compares to prompts, Projects, MCP, and subagents <a class="header-anchor" href="#skills-explained-how-skills-compares-to-prompts-projects-mcp-and-subagents" aria-label="Permalink to &quot;Skills explained: How Skills compares to prompts, Projects, MCP, and subagents&quot;">​</a></h2><p><strong>Date:</strong> 2025-11-13 | <strong>URL:</strong> <a href="https://claude.com/blog/skills-explained" target="_blank" rel="noreferrer">https://claude.com/blog/skills-explained</a></p><h3 id="summary-18" tabindex="-1">Summary <a class="header-anchor" href="#summary-18" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Skill 在 Claude 更廣泛的 Agent 生態系中的定位，以及何時使用 Skill 與 prompt、Projects、MCP 和 subagent 的比較指南。包含競爭情報工作流的完整範例。</p><h3 id="key-points-18" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-18" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>Skill 是動態發現的指令資料夾，補充 prompt、Projects、MCP 和 subagent</li><li>每個 Agent 組件有不同用途：Skill 負責知識、MCP 負責連接、subagent 負責任務委派</li><li>Skill 最適合領域知識和程序知識；Projects 用於共享 context；MCP 用於工具存取</li><li>結合生態系統實現複雜的 Agent 工作流</li></ul>',135)])])}const g=a(l,[["render",o]]);export{m as __pageData,g as default};
